// ── Reward rule prototype (n8n-first approach) ────────────────────────────
// This workflow implements the same streak/coins logic that later migrated into
// server/src/services/rewardService.ts. It shows how we prototype logic in n8n
// before hardening it in Express.
//
// Inputs expected in webhook body:
//   sessionId, studentId, actualDuration (seconds), startedAt (ISO 8601)
//
// This implementation uses static data as a stand-in for the database — in the
// real migration this was replaced by the authoritative SQL recompute in
// rewardService.processRewards.

const body = $input.first().json.body ?? $input.first().json;
const { sessionId, studentId, actualDuration, startedAt } = body;

const COINS_PER_SESSION = 50;

function dateOnly(iso) {
  return iso ? iso.split('T')[0] : null;
}

const state = $getWorkflowStaticData('global');
if (!state.rewards) state.rewards = {};
if (!state.rewards[studentId]) {
  state.rewards[studentId] = { coins: 0, streak: 0, lastDate: null, todayMinutes: 0 };
}

const r = state.rewards[studentId];
const today = dateOnly(new Date().toISOString());
const sessionDate = dateOnly(startedAt);

// Guard: only reward once per session
if (!state.rewardedSessions) state.rewardedSessions = {};
if (state.rewardedSessions[sessionId]) {
  return [{ json: { ok: true, alreadyRewarded: true, rewards: r } }];
}
state.rewardedSessions[sessionId] = true;

// Coins (50 per session, same as the Express implementation)
r.coins += COINS_PER_SESSION;

// Today's minutes
const minutes = Math.floor((actualDuration ?? 0) / 60);
if (sessionDate === today) r.todayMinutes += minutes;
else r.todayMinutes = minutes;

// Streak
if (!r.lastDate) {
  r.streak = 1;
} else {
  const diff = Math.round((new Date(sessionDate) - new Date(r.lastDate)) / 86400000);
  if (diff === 1) r.streak += 1;
  else if (diff > 1) r.streak = 1;
  // diff === 0: same day, streak unchanged
}
r.lastDate = sessionDate;

return [{ json: {
  ok: true,
  sessionId,
  studentId,
  rewards: { ...r },
  message: `Streak now ${r.streak} day${r.streak !== 1 ? 's' : ''}, +${COINS_PER_SESSION} coins.`
} }];
